   108→func (s *APIKey) getFromToken(ctx context.Context, token string) (*apikey.APIKey, error) {
   109→	ctx, span := s.tracer.Start(ctx, "authn.apikey.getFromToken")
   110→	defer span.End()
   111→	decoded, err := satokengen.Decode(token)
   112→	if err != nil {
   113→		return nil, err
   114→	}
   115→
   116→	hash, err := decoded.Hash()
   117→	if err != nil {
   118→		return nil, err
   119→	}
